import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const MyTasks = () => {
  const { user } = useAuth();
  const { tasks, updateTaskProgress } = useData();
  const [tempReasons, setTempReasons] = useState({});
  const [now, setNow] = useState(new Date());

  // Cập nhật thời gian thực mỗi phút để check deadline ngay lập tức
  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const myTasks = tasks.filter(t => t.assigneeId === user.id);

  const handleConfirmUpdate = (taskId, currentProgress) => {
    const reason = tempReasons[taskId] || '';
    if (currentProgress < 90 && !reason.trim()) {
      alert("Thông báo: Bạn bắt buộc phải nhập lý do giải thích khi mức độ hoàn thành dưới 90%!");
      return;
    }
    updateTaskProgress(taskId, currentProgress, reason);
    alert("Cập nhật tiến độ thành công!");
  };

  const formatDate = (dateString) => {
    if (!dateString) return '...';
    return new Date(dateString).toLocaleString('vi-VN', { hour: '2-digit', minute:'2-digit', day: '2-digit', month: '2-digit' });
  };

  return (
    <div>
      <h2>Công việc của tôi</h2>
      {myTasks.length === 0 ? <p>Hiện chưa có công việc được giao.</p> : (
        <div style={{ display: 'grid', gap: '20px' }}>
          {myTasks.map(task => {
            // Logic kiểm tra Quá hạn
            const deadlineDate = new Date(task.deadline);
            const isOverdue = now > deadlineDate;
            const isNotDone = task.progress < 100;
            const isPunished = isOverdue && isNotDone; // Bị phạt nếu quá hạn mà chưa xong 100%

            return (
              <div key={task.id} style={{ 
                border: isPunished ? '2px solid red' : '1px solid #ccc', 
                padding: '20px', 
                borderRadius: '8px', 
                background: 'white',
                position: 'relative'
              }}>
                {/* HEADLINE TASK */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <h3 style={{ margin: '0 0 10px 0', color: '#003366' }}>{task.title}</h3>
                  <span style={{ 
                    padding: '5px 10px', 
                    borderRadius: '15px', 
                    background: task.progress === 100 ? '#d4edda' : '#fff3cd',
                    color: task.progress === 100 ? '#155724' : '#856404',
                    fontWeight: 'bold',
                    fontSize: '0.9rem'
                  }}>
                    {task.progress === 100 ? 'Hoàn thành' : 'Đang làm'}
                  </span>
                </div>

                {/* THÔNG TIN THỜI GIAN & KỶ LUẬT */}
                <div style={{ background: '#f8f9fa', padding: '10px', borderRadius: '5px', marginBottom: '15px', fontSize: '0.9rem' }}>
                  <p style={{ margin: '5px 0' }}>📅 <strong>Bắt đầu:</strong> {formatDate(task.startDate)}</p>
                  <p style={{ margin: '5px 0', color: isOverdue ? 'red' : 'black' }}>
                    ⏳ <strong>Hạn chót:</strong> {formatDate(task.deadline)} {isOverdue && '(Đã hết hạn)'}
                  </p>
                  <p style={{ margin: '5px 0', fontStyle: 'italic', color: '#dc3545' }}>
                    ⚖️ <strong>Hình thức phạt:</strong> {task.penalty}
                  </p>
                </div>

                {/* CẢNH BÁO KỶ LUẬT */}
                {isPunished && (
                  <div style={{ 
                    background: '#ffe6e6', 
                    color: '#721c24', 
                    padding: '10px', 
                    borderRadius: '5px', 
                    marginBottom: '15px',
                    border: '1px solid #f5c6cb',
                    fontWeight: 'bold',
                    textAlign: 'center'
                  }}>
                    ⚠️ CẢNH BÁO: ĐÃ QUÁ HẠN DEADLINE! <br/>
                    HÌNH THỨC KỶ LUẬT ĐÃ ĐƯỢC ÁP DỤNG.
                  </div>
                )}

                {/* CẬP NHẬT TIẾN ĐỘ */}
                <label>Tiến độ hiện tại: <strong>{task.progress}%</strong></label>
                <input 
                  type="range" 
                  min="0" max="100" 
                  value={task.progress} 
                  onChange={(e) => updateTaskProgress(task.id, parseInt(e.target.value), task.reason)}
                  style={{ width: '100%', marginTop: '10px' }}
                />

                {task.progress < 90 && (
                  <div style={{ marginTop: '15px' }}>
                    <p style={{ color: 'red', fontSize: '0.85rem', marginBottom: '5px' }}>
                      * Tiến độ &lt; 90% cần nhập lý do giải thích
                    </p>
                    <textarea
                      placeholder="Nhập lý do tại đây..."
                      value={tempReasons[task.id] !== undefined ? tempReasons[task.id] : task.reason}
                      onChange={(e) => setTempReasons({ ...tempReasons, [task.id]: e.target.value })}
                      style={{ width: '100%', height: '60px', padding: '8px', borderRadius: '4px', border: '1px solid #ff4d4f' }}
                    />
                  </div>
                )}

                <button 
                  onClick={() => handleConfirmUpdate(task.id, task.progress)}
                  style={{ 
                    marginTop: '15px', 
                    padding: '10px 20px', 
                    background: '#1890ff', 
                    color: 'white', 
                    border: 'none', 
                    borderRadius: '4px', 
                    cursor: 'pointer',
                    width: '100%',
                    fontWeight: 'bold'
                  }}
                >
                  Cập nhật tiến độ
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default MyTasks;
